import Link from "next/link";
import { notFound } from "next/navigation";
import { PageFrame } from "@/app/components/site-shell";
import { ProjectGallery } from "@/app/components/project-gallery";
import { getSiteContent } from "@/lib/content-store";

export const dynamic = "force-dynamic";

function youtubeVideo(url: string) {
  if (!url) return null;
  try {
    const parsed = new URL(url);
    const pathId = parsed.pathname.match(/^\/(?:embed|shorts)\/([^/?]+)/)?.[1];
    const id = parsed.hostname.includes("youtu.be") ? parsed.pathname.slice(1).split("/")[0] : parsed.searchParams.get("v") || pathId;
    if (!id || !/^[a-zA-Z0-9_-]{6,}$/.test(id)) return null;
    return { embedUrl: `https://www.youtube.com/embed/${id}`, watchUrl: `https://www.youtube.com/watch?v=${id}` };
  } catch { return null; }
}

function formatDate(value: string) {
  if (!value) return "—";
  const date = new Date(`${value}T00:00:00`);
  return Number.isNaN(date.getTime()) ? value : new Intl.DateTimeFormat("tr-TR", { day: "2-digit", month: "long", year: "numeric" }).format(date);
}

function externalWebsite(url: string) {
  try { const parsed = new URL(url); return parsed.protocol === "http:" || parsed.protocol === "https:" ? parsed.toString() : ""; }
  catch { return ""; }
}

export default async function ProjectDetailPage({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;
  const { projects } = await getSiteContent();
  const project = projects.find((item) => item.slug === slug);
  if (!project) notFound();
  const video = youtubeVideo(project.youtubeUrl);
  const website = externalWebsite(project.projectWebsiteUrl);
  const gallery = [project.coverImageUrl, ...project.galleryUrls]
    .filter((image): image is string => Boolean(image))
    .filter((image, index, images) => images.indexOf(image) === index);
  return <PageFrame>
    <section className="project-detail-hero"><img src={project.coverImageUrl} alt={`${project.title} projesi`} /><div className="project-detail-copy"><p className="eyebrow light"><span>{project.status === "ongoing" ? "DEVAM" : "BİTEN"}</span>{project.year}</p><h1>{project.title}</h1></div></section>
    <section className="content-section project-detail-content">
      <div className="project-overview">
        <div className="project-overview-copy"><p className="eyebrow"><span>PROJE</span> BİLGİLERİ</p><h2>{project.title}</h2><p className="project-summary">{project.summary}</p></div>
        <dl className="project-facts">
          <div><dt>Durum</dt><dd>{project.status === "ongoing" ? "Devam ediyor" : "Tamamlandı"}</dd></div>
          <div><dt>Başlangıç tarihi</dt><dd>{formatDate(project.startDate)}</dd></div>
          <div><dt>Bitiş tarihi</dt><dd>{project.endDate ? formatDate(project.endDate) : "Devam ediyor"}</dd></div>
          <div><dt>Konum</dt><dd>{project.location || "—"}</dd></div>
          <div><dt>İşveren</dt><dd>{project.client || "—"}</dd></div>
          <div><dt>Proje yılı</dt><dd>{project.year}</dd></div>
        </dl>
      </div>
      {project.description && <div className="project-description"><p className="eyebrow"><span>PROJE</span> AÇIKLAMASI</p><p>{project.description}</p></div>}
      <div className="project-links"><Link href="/projeler" className="text-link">Proje arşivine dön <span>↗</span></Link>{website && <a href={website} target="_blank" rel="noreferrer" className="button">Proje web sitesi <span>↗</span></a>}</div>
      {gallery.length > 0 && <div className="project-gallery"><p className="eyebrow"><span>PROJE</span> GALERİSİ</p><ProjectGallery images={gallery} title={project.title} /></div>}
      {video && <div className="project-video"><div className="project-video-heading"><p className="eyebrow"><span>PROJE</span> VİDEOSU</p><a href={video.watchUrl} target="_blank" rel="noreferrer">YouTube’da izle ↗</a></div><div className="video-wrap"><iframe src={video.embedUrl} title={`${project.title} videosu`} allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowFullScreen /></div></div>}
    </section>
  </PageFrame>;
}
